```js
const express = require('express');
const helmet = require('helmet');         // npm install helmet
const rateLimit = require('express-rate-limit'); // npm install express-rate-limit

const app = express();
const PORT = process.env.PORT || 3000;

// ── Security Headers ─────────────────────────────────────────────────────────
app.use(helmet());

// ── Body Parsing with Size Limit ──────────────────────────────────────────────
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// ── Rate Limiting ─────────────────────────────────────────────────────────────
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // max 100 requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// ── CORS (tighten origin in production) ───────────────────────────────────────
app.use((req, res, next) => {
  const allowedOrigin = process.env.ALLOWED_ORIGIN || 'http://localhost:3000';
  res.setHeader('Access-Control-Allow-Origin', allowedOrigin);
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  next();
});

// ── Routes ────────────────────────────────────────────────────────────────────
app.get('/health', (req, res) => {
  // Avoid leaking precise server time; a rounded/relative value is safer.
  res.json({ status: 'ok' });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate & sanitize any query params before use
    const { page, limit } = req.query;

    if (page !== undefined && (isNaN(page) || page < 1)) {
      return res.status(400).json({ error: 'Invalid page parameter' });
    }
    if (limit !== undefined && (isNaN(limit) || limit < 1 || limit > 100)) {
      return res.status(400).json({ error: 'Invalid limit parameter (1–100)' });
    }

    // In a real app, use parameterized queries — never interpolate user input into SQL/NoSQL.
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (err) {
    next(err); // forward unexpected errors to the global handler
  }
});

// ── 404 Handler ───────────────────────────────────────────────────────────────
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ── Global Error Handler ──────────────────────────────────────────────────────
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Log internally (use a real logger like winston/pino in production)
  console.error(`[ERROR] ${req.method} ${req.url}:`, err);

  // Never expose stack traces to the client
  const statusCode = err.status || err.statusCode || 500;
  res.status(statusCode).json({
    error: process.env.NODE_ENV === 'production'
      ? 'An unexpected error occurred'
      : err.message,
  });
});

// ── Server Start ──────────────────────────────────────────────────────────────
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Graceful shutdown — prevents hanging connections
process.on('SIGTERM', () => {
  server.close(() => process.exit(0));
});

module.exports = app;
```

---

### Summary of Changes

| Area | Fix |
|---|---|
| Security headers | `helmet()` middleware |
| Body size limit | `express.json({ limit: '10kb' })` |
| Rate limiting | `express-rate-limit` (100 req / 15 min) |
| CORS | Explicit origin allowlist via env var |
| Input validation | Query param type/range checks with 400 responses |
| Error handling | `try/catch` in routes + global 4-argument error middleware |
| Info disclosure | Removed timestamp from `/health`; stack traces hidden in production |
| Port config | Reads from `process.env.PORT` |
| Graceful shutdown | `SIGTERM` handler closes the server cleanly |

