app.get('/users', query('id').optional().isInt({ min: 1 }).toInt(), (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) return res.status(400).json({ errors: errors.array() });
  // ...
});
```

### 7. 🟡 No CORS Policy
Without explicit CORS config, the behavior is browser-dependent. Be explicit:
```js
const cors = require('cors');
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? [],
  methods: ['GET'],
}));
```

