const PORT = parseInt(process.env.PORT ?? '3000', 10);
const server = app.listen(PORT, () => console.log(`Server on port ${PORT}`));

// Graceful shutdown
process.on('SIGTERM', () => server.close(() => process.exit(0)));
```

